<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div id="modalEditTask" role="dialog" class="modal my-popups right fade rightmodalcssfixs">
            <div role="document" class="modal-dialog mw-800">
                <div class="modal-content">
                    <div class="modal-header mheader-user">
                        <button type="button" class="close" @click="CloseTemplate()">
                            <i class="fa fa-times" aria-hidden="true"></i>
                        </button>

                        <h4 class="modal-title" :title="projectdata.task_name" id="myModalLabel">
                            <template v-if="projectdata.task_type">
                            <span v-if="projectdata.task_type === 'T'">{{ $t('Task') }}</span>
                            <span v-else-if="projectdata.task_type === 'B'">{{ $t('Bug') }}</span>
                            <span v-else-if="projectdata.task_type === 'S'">{{ $t('Story') }}</span>   
                            <span v-else-if="projectdata.task_type === 'SB'">{{ $t('SubTask') }}</span>                            
                            </template>
                            <span v-if="projectdata.task_number || projectdata.task_name">
                                ({{ projectdata.task_number || '' }} 
                                <span v-if="projectdata.task_number && projectdata.task_name"> - </span>
                                {{ projectdata.task_name || '' }})
                            </span>
                        </h4>
                    </div>
                    <loader :is-visible="isLoading"></loader>
                    <div class="modal-body">
                        <div class="bg-white border p-4">
                            <div class="row" v-show="!isDetailEditable">
                                <div class="col-lg-12 mb-3">
                                    <div class="heading-border mt-2">
                                        <h5 class="h5"><span>{{ $t(NewTabName) }}</span>
                                            <small class="float-right" v-show="CheckIsPm">
                                                <a href="javascript:void(0)" title="Edit" @click="isDetailEdit()"
                                                    data-original-title="Edit">
                                                    <i class="fa fa-pencil pr-1"></i> {{ $t('Edit') }}
                                                </a>
                                            </small>
                                        </h5>
                                    </div>
                                </div>
                                <div class="col-sm-12 col-md-6 col-lg-6">   
                                    <div class="form-group">
                                        <label><strong>{{ $t('STATUS_ID') }}:</strong><span
                                                class="answer rightlabeltext ml-1 status-badge status-inprogress">
                                                {{ projectdata.status_name != null ?
                                                    projectdata.status_name : '--' }}</span></label>
                                    </div>
                                </div>

                                <div class="col-sm-12 col-md-6 col-lg-6">
                                    <div class="form-group">
                                        <label><strong>{{ $t('EventPriority') }}:</strong><span
                                                class="answer rightlabeltext ml-1 priority-high">
                                                {{ projectdata.priority_name != null ?
                                                    projectdata.priority_name : '--' }}</span></label>
                                    </div>
                                </div>

                                <div class="col-sm-12 col-md-6 col-lg-6" v-if="SprintButton">
                                    <div class="form-group">
                                        <label><strong>{{ $t('Sprint') }}:</strong><span
                                                class="answer rightlabeltext ml-1"> {{ projectdata.sprint_name != null ?
                                                    projectdata.sprint_name : '--' }}</span></label>
                                    </div>
                                </div>

                                <div class="col-sm-12 col-md-6 col-lg-6"
                                    v-if="projectdata.parent_task_id && projectdata.parent_task_id != 0">
                                    <div class="form-group">
                                        <label><strong>{{ $t('ParentTask') }}:</strong><span
                                                class="answer rightlabeltext ml-1"> <a href="#" class="text-primary">{{
                                                    projectdata.paren_task_name != null ?
                                                        projectdata.paren_task_name : '--' }}</a></span></label>
                                    </div>
                                </div>

                                <div class="col-sm-12 col-md-6 col-lg-6">
                                    <div class="form-group">
                                        <label><strong>{{ $t('EventStartDate') }}:</strong><span
                                                class="answer rightlabeltext ml-1"> {{ projectdata.planned_start_date !=
                                                    null ? $d(new Date(projectdata.planned_start_date)) :
                                                    '--' }}</span></label>
                                    </div>
                                </div>

                                <div class="col-sm-12 col-md-6 col-lg-6">
                                    <div class="form-group">
                                        <label><strong>{{ $t('END_DATE') }}:</strong><span
                                                class="answer rightlabeltext ml-1"> {{ projectdata.planned_end_date !=
                                                    null ? $d(new Date(projectdata.planned_end_date)) :
                                                    '--' }}</span></label>
                                    </div>
                                </div>


                                <div class="col-md-12 col-lg-12">
                                    <div class="form-group">
                                        <label><strong>{{ $t('Description') }}:</strong><span
                                                class="answer rightlabeltext ml-1" :title="projectdata.task_description">{{ projectdata.task_description &&
                                                    projectdata.task_description.trim() !== "" ?
                                                    TruncateStr(projectdata.task_description,160) : '--' }}</span></label>
                                    </div>
                                </div>
                            </div>

                            <div class="col-lg-12 col-md-12 p-0" v-show="isDetailEditable && CheckDisabled()">
                                <dynamic-form ref="dynamicform" lang="en" :buttons="commentButtons" :schema="FormSchema">
                                      <template v-slot:tgslot-Hours="{ data }">
                                        <input type="text" class="form-control"
                                          @keypress="restrictToNumbers($event)"
                                           v-model="Hours" />
                                           <!-- @input="validateWeightage(task, $event)" -->
                                    </template>
                                    <template v-slot:tgslot-TaskDescription="{ data }">
                                        <ckeditor :editor="editor" @ready="onReady" v-model="Descriptionn"></ckeditor>
                                    </template>
                                </dynamic-form>
                            </div>
                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left mb-3 p-0" v-if="CheckDisabled()">
                                <div class="heading-border">
                                    <h5 class="h5"><span id="SProjectDetailTitleSpan">{{$t('TimeTracking')}}</span></h5>
                                </div>
                            </div>
                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left mb-3 p-0" v-if="CheckDisabled()">
                                <div class="hours-grid">
                                    <div class="hours-card">
                                        <!-- {{$t('EstimatedHours')}} -->
                                        <div class="hours-label">{{$t('EstimatedHours')}}:</div>
                                        <div class="hours-value">{{ secondsToHours(projectdata.estimated_hours) }}</div>
                                        <div class="hours-stats">
                                            <span>{{ $t('totalallocated') }}</span>
                                        </div>
                                    </div>

                                    <div class="hours-card">
                                        <!-- {$t('hoursused')}} -->
                                        <div class="hours-label">{{$t('SpentHours')}}:</div>
                                        <div class="hours-value"> {{ secondsToHours(projectdata.HOURSPEND) }}</div>
                                        <div class="hours-stats">
                                            <span>{{
                                                getSpentPercentage(projectdata.estimated_hours, projectdata.HOURSPEND) }}
                                               {{$t('ofEstimated')}}
                                                </span>
                                        </div>
                                    </div>
                                </div>

                                <div class="hours-bar-container">
                                    <!-- <div class="hours-bar" :title="getSpentPercentage(projectdata.estimated_hours, projectdata.HOURSPEND) + '%'">
                                        <div v-if="getSpentPercentage(projectdata.estimated_hours, projectdata.HOURSPEND)"
                                            class="hours-progress"
                                            :style="{ width: getSpentPercentage(projectdata.estimated_hours, projectdata.HOURSPEND) + '%' }">
                                        </div>
                                    </div> -->
                                   <div class="disabled">
                                    <VueSlider  class="no-hover-slider" :min="0" :max="100" v-model="totalPercentage"  />
                                    </div>
                                    <div class="hours-stats">
                                        <span>0 Hours</span>
                                        <span>{{ secondsToHours(projectdata.HOURSPEND) }} </span>
                                        <span>{{ secondsToHours(projectdata.estimated_hours) }} </span>
                                    </div>
                                </div>
                            </div>
                            <div style="clear: both"></div>
                            <div class="collapsible-section mt-3"  v-if="CheckDisabled()">
                                <div class="collapsible-header" @click="toggleCollapseTeam()">
                                    <h3>
                                        {{$t(NewTabName)}}  {{ $t("Team") }}
                                        ({{ TeamData && TeamData.length > 0
                                            ? TeamData.length + ' ' + $t('Members')
                                            : '0'
                                        }})
                                        <small class="float-right font-14"><em
                                                :class="isOpenTeam ? 'fa fa-chevron-down' : 'fa fa-chevron-left'"></em></small>
                                    </h3>
                                </div>
                                <div class="collapsible-content" v-show="isOpenTeam">
                                    <ul class="resource-list">
                                        <li class="resource-item" v-for="item in TeamData" :key="item.task_id">
                                            <div class="resource-avatar">{{ getInitials(item.FULL_NAME) }}</div>
                                            <div class="resource-name">{{ item.FULL_NAME }}</div>
                                            <div class="resource-role">{{ item.DEPARTMENT_NAME }}</div>
                                            <span class="float-right ml-3">
                                                <em v-if="item.ROLE_TYPE == 'Team'"
                                                    class="fa fa-eye text-info pointer  pr-2 mr-4" aria-hidden="true"
                                                    @click="AssignedUser(item)" style="cursor: pointer;"></em>
                                                <em  v-show="CheckIsPm" class="fa fa-trash-o text-danger font-18" aria-hidden="true"
                                                    @click="commonDeleteData(item)"></em>
                                            </span>
                                        </li>
                                    </ul>
                                    <div v-if="TeamData.length == 0"
                                        class="text-center text-danger no_records no-record p-2 border-bottom">
                                        {{ $t('NoRecordfound') }}
                                    </div>
                                    <div class="col-md-12 col-lg-12 p-2 float-left" v-show="CheckIsPm"><a
                                            class="add-checklist-btn float-right w-100"
                                            @click="OpenAddTeamUserPopup()"><em class="fa fa-plus mr-1"></em>{{
                                            $t('Add') }}  {{ $t(TabsArray[1]) }}</a></div>

                                </div>
                            </div>
                            <div class="collapsible-section" v-if="IsShowSubTask && CheckDisabled()">
                                <div class="collapsible-header" @click="toggleCollapseSubTask()">
                                    <h3>
                                        {{ $t("Sub") }} {{ $t(NewTabName) }}
                                        ({{ SubTasks && SubTasks.length > 0
                                            ? SubTasks[0].CompleteTask + '/' + SubTasks.length + ' ' + $t('Completed')
                                            : '0'
                                        }})
                                        <small class="float-right font-14"><em
                                                :class="isOpenSubTask ? 'fa fa-chevron-down' : 'fa fa-chevron-left'"></em></small>
                                    </h3>
                                </div>
                                <div class="collapsible-content" v-show="isOpenSubTask">
                                    <ul class="subtask-list" v-for="(item, index) in SubTasks" :key="index">
                                        <li class="subtask-item">
                                            <em v-if="item.status_name == 'Completed' || item.status_name == 'Closed'"
                                                class="fa fa-check-circle text-success font-20 mr-2"></em>
                                            <label class="form-check form-check-inline" v-else>
                                                <div class="custom-control custom-checkbox custom-control-inline"  v-show="CheckIsPm">
                                                    <input :id="'Checkbox_' + index" type="checkbox"
                                                        class="chkItems custom-control-input"
                                                        :checked="item.status_name == 'Completed' || item.status_name == 'Closed'" />
                                                    <label :for="'Checkbox_' + index"
                                                        class="custom-control-label"></label>
                                                </div>
                                            </label>
                                            <span href="javascript:void(0);" class="subtask-link mt-1 text-primary"
                                                :style="{ textDecoration: item.status_name === 'Completed' || item.status_name == 'Closed' ? 'line-through' : 'none ', cursor: 'pointer' }"
                                                @click="openSubTaskDetails(item)">
                                                {{ item.task_number }} {{ item.task_name }}
                                            </span>

                                            <span @click="DeleteTask(item.task_id)" class="float-right"  v-show="CheckIsPm">
                                                <i class="fa fa-trash-o action-icon font-18 text-danger"
                                                    aria-hidden="true"></i>
                                            </span>
                                        </li>
                                    </ul>
                                    <div v-if="SubTasks.length == 0"
                                        class="text-center text-danger no_records no-record">
                                        {{ $t('NoRecordfound') }}
                                    </div>
                                    <div class="add-subtask" v-show="CheckIsPm">
                                        <input type="text" class="subtask-input" :placeholder="`${$t('Add')} ${$t('New')} ${$t('Sub')} ${$t(NewTabName)}`"
                                            v-model="txtAddSubTask" @keydown.enter="SavetxtAddSubTask"
                                            :disabled="isAddDisabled">
                                        <button class="btn btn-success" @click="SavetxtAddSubTask"
                                            :class="{ 'disabled': txtAddSubTask == '' || isAddDisabled }"
                                            :disabled="txtAddSubTask == '' || isAddDisabled">{{ $t('Add') }}</button>
                                    </div>
                                </div>
                            </div>
                            <div class="collapsible-section" v-if="CheckDisabled()">
                                <div class="collapsible-header" @click="toggleCollapseAddCheckList()">
                                    <h3>
                                         {{$t(NewTabName)}} {{ $t('CheckList') }}
                                        ({{ TaskCheckList && TaskCheckList.length > 0
                                            ? ShowCompletedCheckListCount(TaskCheckList) + '/' + TaskCheckList.length + ' '
                                            +
                                            $t('Completed')
                                            : '0'
                                        }})
                                        <small class="float-right font-14"><em
                                                :class="isOpenAddCheckList ? 'fa fa-chevron-down' : 'fa fa-chevron-left'"></em></small>
                                    </h3>
                                </div>
                                <div v-show="isOpenAddCheckList">                                   
                                    <div class="collapsible-content p-2 border-bottom"
                                        v-for="(name, index) in TaskCheckList" :key="index">
                                        <span :href="'headingOne' + index" v-if="name.TotalCount == name.AnswerCount"><i
                                                class="fa fa-check-circle text-success pr-2 font-20"
                                                aria-hidden="true"></i></span>
                                        <span :href="'headingOne' + index" v-else><i class="fa fa-circle-o pr-2 font-20"
                                                aria-hidden="true"></i></span>

                                        <span
                                            :style="{ textDecoration: name.TotalCount == name.AnswerCount ? 'line-through' : 'none', cursor: 'pointer' }">
                                            <span class="font-weight-400" data-toggle="collapse"
                                                @click="GetChecklistItems(name, index)">
                                                {{ name.checklist_name }}
                                            </span>
                                        </span>
                                        <span class="float-right" @click="DeleteChecklist(name)"  v-show="CheckIsPm">
                                            <i class="fa fa-trash-o action-icon text-danger font-18"
                                                aria-hidden="true"></i>
                                        </span>
                                        <span class="float-right" @click="OpenchecklistItem(name)"  v-show="CheckIsPm">
                                            <i class="fa fa-pencil text-success font-18 pr-3" aria-hidden="true"></i>
                                        </span>
                                        <div class="float-left w-100 my-3" v-show="isOpen(index)">
                                            <div class="accordion-content" v-for="Obj in ItemsData" :key="Obj.id">
                                                <li class="list-unstyled pl-2 py-2"
                                                    :style="{ textDecoration: name.TotalCount == name.AnswerCount ? 'line-through' : 'none' }">
                                                    {{ Obj.title }}</li>
                                            </div>
                                        </div>
                                    </div>
                                    <div v-if="TaskCheckList.length == 0"
                                        class="text-center text-danger no_records no-record">
                                        {{ $t('NoRecordfound') }}
                                    </div>

                                    <div class="col-md-12 col-lg-12 p-2 float-left"  v-show="CheckIsPm"><a
                                            class="add-checklist-btn float-right" @click="AddCheckList"><em
                                                class="fa fa-plus mr-2 "></em>{{ $t('AddChecklist') }}</a></div>
                                </div>
                            </div>

                            <div class="collapsible-section">
                                <div class="collapsible-header" @click="toggleCollapseTaskComment()">
                                    <h3> {{ $t(NewTabName)}} {{ $t("Comments") }} ({{ TaskCommentDetails.length }})
                                        <small class="float-right font-14"><em
                                                :class="isOpenTaskComment ? 'fa fa-chevron-down' : 'fa fa-chevron-left'"></em></small>
                                    </h3>
                                </div>
                                <div class="collapsible-content p-2 float-left w-100" v-show="isOpenTaskComment">
                                    <div class="comment-form col-lg-12 float-left mb-0 p-0"  v-show="CheckIsPm">
                                        <textarea class="comment-textarea" :placeholder="`${$t('Add')} ${$t(NewTabName)} ${$t('Comment')}...`"
                                            v-model="TaskComment" @keydown.enter="SaveTaskComment"></textarea>
                                        <button type="submit" class="comment-submit float-right"
                                            :class="{ 'disabled': TaskComment == '' }" :disabled="TaskComment == ''"
                                            @click="SaveTaskComment">{{ $t('PostComment') }}</button>
                                    </div>
                                    <div class="col-lg-12 mb-3 p-0 float-left">
                                        <div class="heading-border mt-2">
                                            <h5 class="h5"><span>{{$t(NewTabName)}} {{ $t('Comment') }}</span></h5>
                                        </div>
                                    </div>
                                    <ul class="comment-list" v-for="item in TaskCommentDetails" :key="item.id">
                                        <li class="comment-item">
                                            <div class="comment-header">
                                                <div class="comment-avatar">{{ getInitials(item.comment_postedby) }}</div>
                                                <span class="comment-user">{{ item.comment_postedby }}</span>
                                                <span class="comment-time">{{ $d(new Date(item.created_at)) }}</span>
                                                <span class="flexauto"  v-show="CheckIsPm"><a v-if="item.created_by == LoginUserId" href="javascript:;"
                                                        class="float-right font-18" @click="DeleteComment(item.id)"><em
                                                            aria-hidden="true"
                                                            class="fa fa-trash-o text-danger"></em></a>
                                                </span>
                                            </div>
                                            <div class="comment-text decoration">
                                                {{ item.comment }}
                                            </div>
                                        </li>
                                    </ul>
                                    <div v-if="TaskCommentDetails.length == 0"
                                        class="text-center text-danger no_records no-record">
                                        {{ $t('NoRecordfound') }}
                                    </div>
                                </div>
                            </div>
                            <dynamic-form ref="dynamicfileform" lang="en" :buttons="commentButtonss"  :schema="FormSchemaa" >
                                     
                                    </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <AssociateChecklistToTask v-if="isAddCheckList" :TaskId="TaskId" @callbackfunction="CheckListData" :NewTabName="NewTabName"  :TabsArray="TabsArray" :IndustryType_Id="IndustryType_Id">
        </AssociateChecklistToTask>
        <CheckListPreview v-if="IsCheckListPreview" :CheckListitemData="CheckListitemData" :TaskId="TaskId" :NewTabName="NewTabName" :TabsArray="TabsArray">
        </CheckListPreview>
        <AddTeamAndUser v-if="IsAddTeamUser" :ProjectId="ProjectId" :TaskId="TaskId" @close="closeAddTeamPopup"
            @callbackfunction="GetUserTeamData" :NewTabName="NewTabName" :TabsArray="TabsArray"></AddTeamAndUser>
        <AssociateUser v-if="IsUser" :TeamId="TeamId" :NewTabName="NewTabName" :TabsArray="TabsArray"></AssociateUser>
    </section>
</template>
<script>
import DataService from '../../services/DataService'
import AssociateChecklistToTask from '../Modal/AssociateChecklistToTask.vue'
import CheckListPreview from './PreviewChecklist.vue'
import AddTeamAndUser from './AddTeam.vue'
import AssociateUser from './AssociateUser.vue'
import VueApexCharts from 'vue-apexcharts';
export default {
    components: { AssociateChecklistToTask, CheckListPreview, AddTeamAndUser, AssociateUser, VueApexCharts },
    props: {
        projectdata: {
            type: Object,
            required: true
        },
        MainProjectData: {
            type: Object,
            required: false
        },
        isHideSprint: {
            type: Boolean,
            required: true
        },
        isHideConstruction: {
            type: Boolean,
            required: true
        },
        NewTabName:{
            type:String,
            require: true
        },
        TabsArray:{
            type:Array
        },
        checkPmUser: {
            type: Boolean,
            required: true
        },
    },
    data() {

        return {
            projectDataStore: [],
            chartOptions: {
                chart: {
                    id: 'basic-bar',
                    toolbar: {
                        show: false   
                    },
                },
                xaxis: {
                    
                    categories: ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
                }                
            },
            series: [{
                name: 'Hours',
                data: [5, 10, 15, 20, 30, 35, 40]
            }],
             isSavingTask: false,
            isOpenTeam: true,
            isOpenSubTask: true,
            isDetailEditable: true,
            isOpenFile: true,
            isOpenAddCheckList: true,
            isOpenTaskComment: true,
            editor: this.CLASSIC_EDITOR,
            isLoading: false,
            Descriptionn: '',
            txtAddSubTask: '',
            isAddDisabled: false,
            fileName: '',
            FileId:0,
            attachement_mime: '',
            base64String: '',
            fileData: [],
            getFileName:'',
            txtAddCheckList: '',
            FormSchema: [
                {
                    layoutType: "four",
                    //group_name: 'General Information',
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('TaskName'),
                            name: "TaskName",
                            value: "",
                            visibility: true,
                            validationRules: { "required": true, max: 4000 },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Start Date'),
                            name: "planned_start_date",
                            value: "",
                            visibility: true,
                            placeholder: this.$t("Start Date"),
                            validationRules: {
                                "required": false
                            },
                            config: { mode: "date", format: "M/D/YYYY",minDate:'', maxDate:'',onChange: this.onChangeStartDate }
                        },
                        {
                            astype: "DateField",
                            label: this.$t("End Date"),
                            name: "planned_end_date",
                            value: "",
                            placeholder: this.$t("End Date"),
                            visibility: true,
                            validationRules: {
                                required: false,
                            },
                            config: { mode: "date", format: "M/D/YYYY",minDate:'', maxDate:'',onChange: this.onChangeCountHours }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Status'),
                            visibility: true,
                            name: "StatusId",
                            value: "",
                            validationRules: { "required": false, max: 4000 },
                            config: { options: [] }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Team'),
                            name: "Team",
                            value: "",
                            placeholder: "",
                            config: {
                                showAddIcon: true,
                                options: []
                            },
                            validationRules: {
                                "required": false
                            },
                            visibility: false,
                            disabled: false,

                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t('Assign User'),
                            name: "AssignUser",
                            mode: "tag",
                            multiple: false,
                            value: "",
                            config: {
                                options: []
                            },
                            visibility: false,
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Sprint'),
                            name: "Sprint",
                            value: "",
                            placeholder: "",
                            visibility: true,
                            config: {
                                options: []
                            },
                            validationRules: {
                                "required": false
                            },
                            disabled: false,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Priority'),
                            name: "Priority",
                            value: "",
                            placeholder: "",
                            visibility: true,
                            config: {
                                options: []
                            },
                            validationRules: {
                                "required": false
                            },
                            disabled: false,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Parent'),
                            name: "Parent",
                            visibility: true,
                            value: "",
                            placeholder: "",
                            config: {
                                options: []
                            },
                            validationRules: {
                                "required": false
                            },
                            disabled: true,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Stage'),
                            name: "Stage",
                            visibility: false,
                            value: "",
                            placeholder: "",
                            config: {
                                options: []
                            },
                            validationRules: {
                                "required": false
                            },
                            disabled: false,
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('Hours'),
                            name: "Hours",
                            value: "",
                            visibility: true,
                            validationRules: { "required": true, max: '' },
                            disabled: false,
