        secondsToHours(seconds) {
            if (isNaN(seconds) || seconds < 0) return "0 Hours 0 Min";
            let hours = Math.floor(seconds / 3600);
            let minutes = Math.floor((seconds % 3600) / 60);
            return `${hours} Hours ${minutes} Min`;
        },
        secondsToHourss(seconds) {
            if (isNaN(seconds) || seconds < 0) return "0";
            let hours = Math.floor(seconds / 3600);
            return `${hours}`;
        },
        getTotalHours(startDate, endDate) {
            let start = new Date(startDate);
            let end = new Date(endDate);
            let diffMs = end - start;
            let hours = diffMs / (1000 * 60 * 60);
            return hours;
        },
        getWorkingDays(totalHours, shiftHours = 9) {
            return Math.ceil(totalHours / shiftHours);
        },
        getSetPercentage()
        {
            if (
                !this.projectdata.estimated_hours ||
                isNaN(this.projectdata.estimated_hours) ||
                this.projectdata.estimated_hours <= 0 ||
                !this.projectdata.HOURSPEND ||
                isNaN(this.projectdata.estimated_hours) ||
                this.projectdata.HOURSPEND <= 0
            ) {
                return null;
            }

            const percentage = (this.projectdata.HOURSPEND / this.projectdata.estimated_hours) * 100;
            this.totalPercentage= Math.min(percentage, 100).toFixed(2);
        },
        getSpentPercentage(estimatedHours, spentHours) {
            if (
                !estimatedHours ||
                isNaN(estimatedHours) ||
                estimatedHours <= 0 ||
                !spentHours ||
                isNaN(spentHours) ||
                spentHours <= 0
            ) {
                return null;
            }

            const percentage = (spentHours / estimatedHours) * 100;
            return Math.min(percentage, 100).toFixed(2);
        },
