        SaveTask:async function () {
            var vm = this;
            var checkTotalWeightage=0;
            var TaskName = vm.FormSchema[0].Data[0].value;
            var StartDate = vm.FormSchema[0].Data[1].value;
            var EndtDate = vm.FormSchema[0].Data[2].value;
            var Status = vm.FormSchema[0].Data[3].value;
            var Sprint = vm.FormSchema[0].Data[6].value == '' ? 0 : vm.FormSchema[0].Data[6].value;
            var Priority = vm.FormSchema[0].Data[7].value;
            var weightage = vm.FormSchema[0].Data[11].value; 
            var oldWeightage =vm.projectdata.weightage;
            checkTotalWeightage = vm.projectdata.TotalWeightage;
            checkTotalWeightage -= parseInt(oldWeightage);
            checkTotalWeightage += parseInt(weightage); 
            if (checkTotalWeightage > 100 && vm.IndustryType_Name == 'Construction') {
                vm.ShowAlert(vm.$t('TotalWeightageRange'), "failure", true, vm.$t("Alert"));
                return;
            }
            if (StartDate && EndtDate) {
                const start = new Date(StartDate);
                const end = new Date(EndtDate);
                start.setHours(0, 0, 0, 0);
                end.setHours(0, 0, 0, 0);
                if (start > end) {
                    vm.ShowAlert(vm.$t('Enddatecannot'), "failure", true, vm.$t("Alert"));
                    return;
                }
            }

            //   vm.isLoading = true;
              vm.isDetailEditable = false;
            var stage_id =vm.FormSchema[0].Data[9].value;
            var Hours = vm.Hours;
            var Description =  vm.Descriptionn !=null ?  vm.Descriptionn.trim().replace(/<[^>]+>/g, '').replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&').replace(/&lt;/gi, '<').replace(/&gt;/gi, '>'): ''
            var obj = {
                TaskId: vm.projectdata.task_id,
                Project_id: vm.projectdata.project_id,
                TaskName: TaskName,
                StartDate: StartDate,
                Stageid:stage_id,
                EndDate: EndtDate,
                SprintId: Sprint,
                PriorityId: Priority,
                StatusId: Status,
                UserId: vm.Users,
                BackLogDescription: Description,
                EHours: Hours,
                Weightage:weightage
            }
            var globalhours=vm.getTotalHoursBetweenDates(vm.gloabStartDate,vm.gloabEndDate)
            var hoursbetweendate=vm.getTotalHoursBetweenDates(obj.StartDate,obj.EndDate)
            if(parseFloat(hoursbetweendate) > parseFloat(globalhours))
            {
                vm.isLoading = false;
                 vm.ShowAlert([vm.$t("tasktotalhours"), vm.$t(vm.ProjectTotalHours)], "failure", vm.$t('Alert'));
                 return;
            }
                     var objectPostString = JSON.stringify(obj);
                await DataService.UpdateTask(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response && response.data.status == "Success") {
                            if(response.data.result=='INVALID_WEIGHTAGE')
                            {
                                vm.ShowAlert(vm.$t('Subtask weightage cannot be greater than the parent tasks weightage.', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                                return;
                            }
                            else if(response.data.result=='Update')
                            {
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t(vm.NewTabName)]), "success", true, vm.$t("Alert"));
                            }
                            else if(response.data.result=='EXIST')
                            {
                                vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Task')]), "warning", true, vm.$t("Alert"));
                            }
                        
                            if(vm.projectdata.parent_task_id == 0){
                            vm.UpdateTaskDetails();
                                vm.$emit('callbackfunction');
                            }
                            else{
                                vm.GetSubTaskDetails(vm.projectdata.task_id,vm.projectdata.parent_task_id);
                                vm.UpdateTaskDetails();
                                vm.$emit('callbackfunction');
                            }
                        }else {
                            vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                        }
                    })
           
        },
