        UploadFile: async function (evt) {
                try {
                    var vm = this;
                    vm.fileData = [];
                    for (var i = 0; i < evt.length; i++) {
                        vm.file = evt[i];
                    }
                    const formData = new FormData();
                    formData.append('file', vm.file);
